using UnityEngine;

/// <summary>
/// Define um upgrade desbloqueável para uso em condições ("upgrade activo")
/// e na ação "Desbloquear Upgrade".
/// </summary>
[CreateAssetMenu(menuName = "Animals/Upgrade Data", fileName = "NewUpgrade")]
public class UpgradeData : ScriptableObject
{
    [Header("Identidade")]
    public string upgradeId;
    public string displayName;

    [Header("Apresentação")]
    [TextArea] public string description;
    public Sprite icon;

    [Header("Instinto (ligar/desligar)")]
    [Tooltip("Se true, este upgrade é um 'Instinto' que o jogador pode ligar/desligar livremente depois de comprado (Menu de Pausa > Itens e Instintos). Se false, fica sempre activo depois de desbloqueado. Estado guardado em PlayerProgress.enabledUpgradeIds.")]
    public bool toggleable = false;

    [Header("Economia (Tarefa #20)")]
    [Tooltip("Custo para desbloquear este upgrade via Action_BuyUpgrade (Eventos de NPC). 0 = sem custo — desbloqueio continua possível de graça via Action_UnlockUpgrade (recompensa de missão/desafio/diálogo).")]
    [Min(0)] public int unlockCost = 0;

    [Tooltip("Recurso de PlayerProgress gasto ao comprar este upgrade (Action_BuyUpgrade). Irrelevante se 'unlockCost' for 0.")]
    public PlayerResourceType unlockCurrency = PlayerResourceType.Sementes;
}
